      setState(prev => ({ ...prev, error: "Please upload a valid audio file." }));
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = (event.target?.result as string).split(',')[1];
      setFile({
        name: selectedFile.name,
        size: selectedFile.size,
        type: selectedFile.type,
        base64: base64
      });
      setState(prev => ({ ...prev, error: null, srtContent: null }));
    };
    reader.readAsDataURL(selectedFile);
  };

  const processAudio = async () => {
    if (!file) return;

    setState(prev => ({ ...prev, isProcessing: true, error: null, progress: 'Uploading and Analyzing...' }));

    try {
      const result = await generateHinglishSrt(file.base64, file.type);
      setState(prev => ({ 
        ...prev, 
        isProcessing: false, 
        srtContent: result, 
        progress: 'Finished' 
      }));
    } catch (err) {
      setState(prev => ({ 
        ...prev, 
        isProcessing: false, 
        error: err instanceof Error ? err.message : "Something went wrong.",
        progress: 'Failed'
      }));
    }
  };

  const downloadSrt = () => {
    if (!state.srtContent) return;
    const blob = new Blob([state.srtContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${file?.name.split('.')[0] || 'subtitles'}.srt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const reset = () => {
    setFile(null);
    setState({
      isProcessing: false,
      error: null,
      srtContent: null,
      progress: 'Idle'
    });
