                        </svg>
                        Download .SRT File
                      </Button>
                      <Button variant="secondary" className="sm:w-auto px-8" onClick={reset}>
                        Start Over
                      </Button>
                    </div>

                    <div className="mt-8">
                      <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-3">Preview Transcript</h3>
                      <div className="bg-slate-900 rounded-2xl p-6 overflow-auto max-h-[300px] shadow-inner font-mono text-sm text-indigo-300">
                        <pre className="whitespace-pre-wrap">{state.srtContent}</pre>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </Card>

        {/* Info Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="p-6 bg-white rounded-2xl border border-slate-100 shadow-sm">
            <h4 className="font-bold text-slate-800 mb-2">Fast Transcription</h4>
            <p className="text-sm text-slate-500">Powered by Gemini 3 Flash for near-instant results.</p>
          </div>
          <div className="p-6 bg-white rounded-2xl border border-slate-100 shadow-sm">
            <h4 className="font-bold text-slate-800 mb-2">Smart Hinglish</h4>
            <p className="text-sm text-slate-500">Intelligently blends Hindi grammar with English vocabulary.</p>
          </div>
          <div className="p-6 bg-white rounded-2xl border border-slate-100 shadow-sm">
            <h4 className="font-bold text-slate-800 mb-2">Ready to Use</h4>
            <p className="text-sm text-slate-500">Standard SRT format compatible with VLC, YouTube, and Premiere.</p>
          </div>
        </div>

        <footer className="text-center text-slate-400 text-sm pb-12">
          Made with ❤️ for Indian creators
        </footer>
      </div>
    </div>
  );
};

